import React, { useState, useEffect } from 'react';

const Home = () => {
  const [equipos, setEquipos] = useState([]);
  const [busqueda, setBusqueda] = useState("");
  const [favs, setFavs] = useState([]);

  // Estados para el Modal (Cuadro que sobresale)
  const [equipoSeleccionado, setEquipoSeleccionado] = useState(null);
  const [mostrarModal, setMostrarModal] = useState(false);

  useEffect(() => {
    fetch("https://site.api.espn.com/apis/site/v2/sports/basketball/nba/teams")
      .then(res => res.json())
      .then(data => {
        setEquipos(data.sports[0].leagues[0].teams);
      });

    // Cargar favoritos guardados
    const guardados = JSON.parse(localStorage.getItem("nba_favs")) || [];
    setFavs(guardados);
  }, []);

  // Lógica de Favoritos (Toggle)
  const alternarFavorito = (id) => {
    let nuevosFavs;
    if (favs.includes(id)) {
      nuevosFavs = favs.filter(favId => favId !== id);
    } else {
      nuevosFavs = [...favs, id];
    }
    setFavs(nuevosFavs);
    localStorage.setItem("nba_favs", JSON.stringify(nuevosFavs));
  };

  // Función para abrir modal con info
  const abrirInfo = (equipo) => {
    setEquipoSeleccionado(equipo);
    setMostrarModal(true);
  };

  const equiposFiltrados = equipos.filter(item => 
    item.team.displayName.toLowerCase().includes(busqueda.toLowerCase())
  );

  return (
    <div className="main-content">
      <h1 style={{ textAlign: 'center', color: '#1d428a' }}>Equipos NBA</h1>

      <div className="search-container">
        <input 
          type="text" 
          className="search-input"
          placeholder="Buscar equipo..." 
          onChange={(e) => setBusqueda(e.target.value)}
        />
      </div>

      <div className="teams-grid">
        {equiposFiltrados.map((t) => {
          const esFav = favs.includes(t.team.id);
          return (
            <div key={t.team.id} className="team-card">
              <img src={t.team.logos[0].href} alt="" className="team-logo" />
              <h3>{t.team.displayName}</h3>

              <div className="btn-container">
                <button 
                  className="btn-main"
                  style={{ backgroundColor: `#${t.team.color}` }}
                  onClick={() => abrirInfo(t.team)}
                >
                  VER INFO
                </button>
                <button 
                  className="btn-fav"
                  onClick={() => alternarFavorito(t.team.id)}
                  style={{ color: esFav ? '#ef426f' : '#ccc', borderColor: esFav ? '#ef426f' : '#ddd' }}
                >
                  {esFav ? '❤️' : '🤍'}
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {/* --- MODAL DE INFORMACIÓN (CUADRO QUE SOBRESALE) --- */}
      {mostrarModal && equipoSeleccionado && (
        <div className="modal-overlay" onClick={() => setMostrarModal(false)}>
          <div className="modal-content" onClick={e => e.stopPropagation()} style={{ borderTop: `10px solid #${equipoSeleccionado.color}` }}>
            <button className="close-btn" onClick={() => setMostrarModal(false)}>×</button>
            <img src={equipoSeleccionado.logos[0].href} alt="" width="120" />
            <h2>{equipoSeleccionado.displayName}</h2>
            <p><strong>Abreviación:</strong> {equipoSeleccionado.abbreviation}</p>
            <p><strong>Ciudad:</strong> {equipoSeleccionado.location}</p>
            <p><strong>ID del Equipo:</strong> {equipoSeleccionado.id}</p>
            <div style={{ backgroundColor: `#${equipoSeleccionado.alternateColor}`, padding: '10px', borderRadius: '5px', color: 'white', marginTop: '10px' }}>
              Color Alternativo: #{equipoSeleccionado.alternateColor}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Home;
